<template><div class="page"><header class="page-head"><div><h1>Releases</h1><p>{{ request?.title||'Recherche Sonarr / Radarr' }}</p></div><button class="icon-button" :disabled="loading" title="Actualiser" @click="load"><RefreshCw :class="{spin:loading}"/></button></header><p v-if="error" class="notice error-text">{{ error }}</p><section class="panel release-list"><template v-for="(release,index) in releases" :key="release.guid"><div v-if="index===firstEnglish" class="release-divider">Resultats anglais / non VF</div><article class="release-row" :class="{french:release.is_french}"><div><strong>{{ release.title }}</strong><span>{{ release.indexer||'Indexeur' }} - {{ release.quality||release.protocol||'-' }}</span><small v-if="release.rejections?.length">{{ release.rejections.join(', ') }}</small></div><div class="release-stats"><span>{{ formatSize(release.size) }}</span><span>{{ release.seeders||0 }} seeds</span><span>CF {{ release.custom_format_score||0 }}</span></div><button class="icon-button" :disabled="grabbing===release.guid" title="Grab" @click="grab(release)"><Download :class="{spin:grabbing===release.guid}"/></button></article></template><p v-if="!loading&&releases.length===0" class="empty">Aucune release disponible.</p></section></div></template>
<script setup>import { computed,onMounted,ref } from "vue";import { Download,RefreshCw } from "@lucide/vue";import { useRoute } from "vue-router";import { api } from "@/api";const route=useRoute(),request=ref(null),releases=ref([]),loading=ref(false),grabbing=ref(null),error=ref('');const firstEnglish=computed(()=>releases.value.findIndex(r=>!r.is_french));function formatSize(v){if(!v)return'-';return `${(v/1024/1024/1024).toFixed(1)} Go`}async function load(){loading.value=true;error.value='';try{request.value=await api(`/api/requests/${route.params.requestId}`);if(!request.value.arr_id)throw new Error('Ce media n\'est pas encore lie a Sonarr ou Radarr');const p=new URLSearchParams({media_type:request.value.media_type,arr_id:request.value.arr_id});if(request.value.arr_instance_id)p.set('instance_id',request.value.arr_instance_id);releases.value=await api(`/api/arr/releases?${p}`)}catch(e){error.value=e.message;releases.value=[]}finally{loading.value=false}}async function grab(release){if(grabbing.value)return;grabbing.value=release.guid;const tab=window.open('about:blank','_blank');if(tab)tab.opener=null;error.value='';try{await api('/api/arr/grab',{method:'POST',body:JSON.stringify({media_type:request.value.media_type,guid:release.guid,indexer_id:release.indexer_id,instance_id:request.value.arr_instance_id,request_id:request.value.id})});if(tab)tab.location.href='/app/downloads'}catch(e){if(tab)tab.close();error.value=e.message}finally{grabbing.value=null}}onMounted(load);</script>
